import { useState, useEffect, useRef } from "react";
import 'bootstrap-icons/font/bootstrap-icons.css';

//Este es el editor de Quill (formato de texto)
function EditorQuill({ placeholder, onReady, initialContent = "" }) {
  const contenedor = useRef(null);
  const iniciado = useRef(false);

  useEffect(() => {
    if (iniciado.current) return;
    iniciado.current = true;

    const Parchment = window.Quill.import("parchment");
    const AlignStyle = new Parchment.Attributor.Style(
      "align", "text-align",
      { scope: Parchment.Scope.BLOCK, whitelist: ["left", "center", "justify"] }
    );
    window.Quill.register(AlignStyle, true);

    const quill = new window.Quill(contenedor.current, {
      theme: "snow",
      placeholder: placeholder || "Escribe aquí...",
      modules: {
        toolbar: [
          ["bold", "italic", "underline"],
          [{ align: '' }, { align: 'center' }, { align: 'justify' }],
          [{ color: [COLOR_PRINCIPAL, "#000000", "#C00000"] }, { background: [] }],
          [{ list: "ordered" }, { list: "bullet" }],
          ["link"],
          ["clean"],
        ],
      },
    });
    if (initialContent) {
      quill.root.innerHTML = initialContent;
    }

    onReady(quill);
  }, []);

  return (
    <div style={{ position: "relative" }}>
      <div ref={contenedor} style={{ background: "#ffffff", height: 150, overflowY: "auto" }} />
    </div>
  );
}
