function crearCorreoVacio() {
  return {
    id: Date.now(),
    fechaCreacion: new Date().toISOString(),
    fechaModificacion: new Date().toISOString(),
    titulo: "",
    tituloVa: "",
    imagenCabecera: "",
    imagenCabeceraVa: "",
    hojaVaActiva: false,
    bloques: [],
  };
}

function serializarCorreo(correo) {
  return {
    ...correo,
    fechaModificacion: new Date().toISOString(),
    bloques: correo.bloques.map(b => ({ ...b })),
  };
}

//Componente principal de la aplicación
export default function App() {
  const [titulo, setTitulo] = useState("");
  const [tituloVa, setTituloVa] = useState("");
  const [imagenCabecera, setImagenCabecera] = useState("");
  const [imagenCabeceraVa, setImagenCabeceraVa] = useState("");

  const [bloques, setBloques] = useState([]);

  const [hojaVaActiva, setHojaVaActiva] = useState(false);

  const [quillCargado, setQuillCargado] = useState(false);
  const [html, setHtml] = useState("");
  const [copiado, setCopiado] = useState(false);
  const [pestanaActiva, setPestanaActiva] = useState("es");

  const [correosGuardados, setCorreosGuardados] = useState(() => {
    try {
      const guardados = localStorage.getItem("correosGuardados");
      return guardados ? JSON.parse(guardados) : [];
    } catch {
      return [];
    }
  });
  const [correoEditandoId, setCorreoEditandoId] = useState(null);
  const [mostrarListaCorreos, setMostrarListaCorreos] = useState(false);

  const [hoveredCorreoId, setHoveredCorreoId] = useState(null);
  const [pendienteAccion, setPendienteAccion] = useState(null); // { tipo: "nuevo" | "cargar", correo? }

  const editoresQuill = useRef({});
  const iframeRef = useRef(null);
  const iframeInicializado = useRef(false);


  useEffect(() => {
    const resetStyle = document.createElement("style");
    resetStyle.textContent = "*, *::before, *::after { box-sizing: border-box; } html, body, #root { margin: 0; padding: 0; width: 100%; height: 100%; overflow: hidden; }";
    document.head.appendChild(resetStyle);

    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://cdn.quilljs.com/1.3.7/quill.snow.css";
    document.head.appendChild(link);

    const script = document.createElement("script");
    script.src = "https://cdn.quilljs.com/1.3.7/quill.min.js";
    script.onload = () => setQuillCargado(true);
    document.head.appendChild(script);
  }, []);

  useEffect(() => {
    setHtml(generarHTML());
    const iframe = iframeRef.current;
    if (!iframe) return;
    const doc = iframe.contentDocument || iframe.contentWindow.document;

    if (!iframeInicializado.current) {
      iframeInicializado.current = true;
      doc.open();
      doc.write("<html><head></head><body style='margin:0;padding:0;background:#F2F4F7;'></body></html>");
      doc.close();
    }
    if (doc && doc.body) {
      const scrollY = iframe.contentWindow.scrollY || 0;
      doc.body.innerHTML = generarBodyHTML();
      doc.body.style.margin = "0";
      doc.body.style.padding = "0";
      doc.body.style.background = "#F2F4F7";
      iframe.contentWindow.scrollTo(0, scrollY);
    }
  }, [bloques, titulo, tituloVa, imagenCabecera, imagenCabeceraVa, hojaVaActiva]);

  useEffect(() => {
    try {
      localStorage.setItem("correosGuardados", JSON.stringify(correosGuardados));
    } catch (e) {
      alert("No se pudo guardar: almacenamiento local lleno.");
    }
  }, [correosGuardados]);

  function hayCorreoActivo() {
    return titulo.trim() !== "" || tituloVa.trim() !== "" || imagenCabecera.trim() !== "" || imagenCabeceraVa.trim() !== "" || bloques.length > 0;
  }

  function guardarCorreo() {
    const correoActual = serializarCorreo({
      id: correoEditandoId ?? Date.now(),
      fechaCreacion: correoEditandoId
        ? (correosGuardados.find(c => c.id === correoEditandoId)?.fechaCreacion ?? new Date().toISOString())
        : new Date().toISOString(),
      fechaModificacion: new Date().toISOString(),
      titulo,
      tituloVa,
      imagenCabecera,
      imagenCabeceraVa,
      hojaVaActiva,
      bloques,
    });

    if (correoEditandoId) {
      setCorreosGuardados(prev =>
        prev.map(c => c.id === correoEditandoId ? correoActual : c)
      );
    } else {
      setCorreosGuardados(prev => [...prev, correoActual]);
      setCorreoEditandoId(correoActual.id);
    }
    // Cuando tengas BD: await fetch('/api/correos', { method: 'POST', body: JSON.stringify(correoActual) })
    alert(`Correo "${correoActual.titulo || correoActual.tituloVa || "Sin título"}" guardado correctamente.`);
  }

  function cargarCorreo(correo) {
    if (hayCorreoActivo() && correoEditandoId !== correo.id) {
      if (window.confirm("¿Quieres guardar el correo actual antes de continuar?")) {
        guardarCorreo();
      }
    }
    ejecutarCargarCorreo(correo);
  }

  function ejecutarCargarCorreo(correo) {
    editoresQuill.current = {};
    iframeInicializado.current = false;
    setTitulo(correo.titulo);
    setTituloVa(correo.tituloVa);
    setImagenCabecera(correo.imagenCabecera);
    setImagenCabeceraVa(correo.imagenCabeceraVa);
    setHojaVaActiva(correo.hojaVaActiva);
    setBloques(correo.bloques.map(b => ({ ...b })));
    setCorreoEditandoId(correo.id);
    setPestanaActiva("es");
    setMostrarListaCorreos(false);
  }

  function eliminarCorreoGuardado(id) {
    if (!confirm("¿Eliminar este correo guardado?")) return;
    setCorreosGuardados(prev => prev.filter(c => c.id !== id));
    if (correoEditandoId === id) nuevoCorreo();
    // Cuando tengas BD: await fetch(`/api/correos/${id}`, { method: 'DELETE' })
  }

  function nuevoCorreo() {
    if (hayCorreoActivo()) {
      if (window.confirm("¿Quieres guardar el correo actual antes de continuar?")) {
        guardarCorreo();
      }
    }
    ejecutarNuevoCorreo();
  }

  function ejecutarNuevoCorreo() {
    editoresQuill.current = {};
    iframeInicializado.current = false;
    setTitulo("");
    setTituloVa("");
    setImagenCabecera("");
    setImagenCabeceraVa("");
    setHojaVaActiva(false);
    setBloques([]);
    setCorreoEditandoId(null);
    setPestanaActiva("es");
  }

  function formatearFecha(iso) {
    return new Date(iso).toLocaleString("es-ES", {
      day: "2-digit", month: "2-digit", year: "numeric",
      hour: "2-digit", minute: "2-digit"
    });
  }

  function comprimirImagen(archivo, maxWidth = 600, quality = 0.8) {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement("canvas");
          const escala = Math.min(1, maxWidth / img.width);
          canvas.width = img.width * escala;
          canvas.height = img.height * escala;
          canvas.getContext("2d").drawImage(img, 0, 0, canvas.width, canvas.height);
          resolve(canvas.toDataURL("image/jpeg", quality));
        };
        img.src = e.target.result;
      };
      reader.readAsDataURL(archivo);
    });
  }


  async function imagenCabeceraABase64(archivo, esVa = false) {
    const comprimida = await comprimirImagen(archivo, 600, 1);
    if (archivo.maxWidth > 600) {
      return;
    }
    if (esVa) setImagenCabeceraVa(comprimida);
    else setImagenCabecera(comprimida);
  }

  function agregarBloque(tipo) {
    setBloques(prev => [...prev, {
      id: Date.now(),
      tipo,
      contenido: "",
      imagen: "",
      urlBoton: "",
      textoBoton: "Más información",
      colorBoton: COLOR_PRINCIPAL,
      contenidoCol2: "",
      contenidoVa: "",
      imagenVa: "",
      urlBotonVa: "",
      textoBotonVa: "Més informació",
      colorBotonVa: COLOR_PRINCIPAL,
      contenidoCol2Va: "",
    }]);
  }

  function actualizarBloque(id, campo, valor) {
    setBloques(prev => prev.map(b => b.id === id ? { ...b, [campo]: valor } : b));
  }

  function eliminarBloque(id) {
    ["contenido", "contenidoVa", "contenidoCol2", "contenidoCol2Va"].forEach(c => {
      delete editoresQuill.current[id + "-" + c];
    });
    setBloques(prev => prev.filter(b => b.id !== id));
  }

  function imagenBloqueABase64(id, archivo, campoImagen) {
    const reader = new FileReader();
    reader.onload = e => actualizarBloque(id, campoImagen, e.target.result);
    reader.readAsDataURL(archivo);
  }

  function guardarEditor(id, campo, quill) {
    const key = id + "-" + campo;
    editoresQuill.current[key] = quill;
    quill.on("text-change", () => {
      actualizarBloque(id, campo, quill.root.innerHTML);
    });
  }

  function copiarHTML() {
    navigator.clipboard.writeText(html).then(() => {
      setCopiado(true);
      setTimeout(() => setCopiado(false), 2000);
    });
  }

  function estilizarContenido(html) {
    return html
      .replace(/<p /g, '<p style="margin:0 0 10px 0; font-family:Arial,sans-serif; font-size:14px; line-height:19px; color:#53565A;" ')
      .replace(/<p>/g, '<p style="margin:0 0 10px 0; font-family:Arial,sans-serif; font-size:14px; line-height:19px; color:#53565A;">');
  }

  // Función para renderizar los bloques en formato HTML
  function renderBloquesHTML(sufijo) {
    let contenidoBloques = "";
    bloques.forEach(b => {
      const contenido = estilizarContenido(b["contenido" + sufijo] || "");
      const imagen = b["imagen" + sufijo] || "";
      const urlBoton = b["urlBoton" + sufijo] || "";
      const textoBoton = b["textoBoton" + sufijo] || "";
      const colorBoton = b["colorBoton" + sufijo] || COLOR_PRINCIPAL;
      const contenidoCol2 = estilizarContenido(b["contenidoCol2" + sufijo] || "");

      if (b.tipo === "texto") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px; font-family:Arial,sans-serif; font-size:14px; color:#53565A; line-height:20px; word-break:break-word; overflow-wrap:break-word;">
            ${contenido}
          </td>
        </tr>`;
      } else if (b.tipo === "imagen") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px; text-align:center;">
            <img src="${imagen}" alt="imagen" width: "300" style="height:auto; max-width:552px; margin: 0 auto;">
          </td>
        </tr>`;
      } else if (b.tipo === "doscolumnas") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px;">
            <table width="100%" cellspacing="0" cellpadding="0" border="0">
              <tr>
                <td width="50%" valign="top" style="border:1px solid #E5E7EB; padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; word-break:break-word; overflow-wrap:break-word;">
                  ${contenido}
                </td>
                <td width="50%" valign="top" style="border:1px solid #E5E7EB; padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; word-break:break-word; overflow-wrap:break-word;">
                  ${contenidoCol2}
                </td>
              </tr>
            </table>
          </td>
        </tr>`;
      } else if (b.tipo === "caja") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px;">
            <table width="100%" cellspacing="0" cellpadding="0" border="0" style="border-left:4px solid ${COLOR_PRINCIPAL}; background:#EEF5FD;">
              <tr>
                <td style="padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; line-height:19px; word-break:break-word; overflow-wrap:break-word;">
                  ${contenido}
                </td>
              </tr>
            </table>
          </td>
        </tr>`;
      } else if (b.tipo === "boton") {
        contenidoBloques += `
        <tr>
          <td align="center" style="padding:16px 24px;">
            <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="border-collapse:separate;">
              <tr>
                <td align="center" bgcolor="${colorBoton}" style="border-radius:3px; width:250px; height:40px;">
                  <a href="${urlBoton}"
                    style="display:inline-block;
                           width:270px;
                           height:40px;
                           line-height:40px;
                           font-family:Arial,sans-serif;
                           font-size:15px;
                           font-weight:bold;
                           color:#ffffff;
                           text-align:center;
                           text-decoration:none;
                           border-radius:3px;">
                    ${textoBoton}
                  </a>
                </td>
              </tr>
            </table>
          </td>
        </tr>`;
      }
    });
    return contenidoBloques;
  }
  // Función para generar la hoja HTML completa
  function generarHoja(tit, imgCab, sufijo, conPie) {
    const cabecera = imgCab
      ? `<img src="${imgCab}" alt="cabecera" style="max-width:100%; width:auto; height:auto; display:block; margin:0 auto;"/>`
      : `<img src="${LOGO_CABECERA}" alt="logo" style="height:auto; max-width:300px; margin-top:0px; margin-bottom:0px">`;

    const paddingCabecera = imgCab ? "border-top:6px solid " + COLOR_PRINCIPAL + "; border-bottom:1px solid #E5E7EB;" : "padding:22px 24px; border-top:6px solid " + COLOR_PRINCIPAL + "; border-bottom:1px solid #E5E7EB;";

    return `
      <table width="600" cellspacing="0" cellpadding="0" border="0" bgcolor="#FFFFFF" style="border-collapse:collapse;">
        <tr>
          <td style="${paddingCabecera} text-align:center;">
            ${cabecera}
          </td>
        </tr>
        <tr>
          <td style="padding:18px 24px 10px 24px; text-align:center;">
            <h1 style="margin:0; font-family:Arial,sans-serif; font-size:20px; color:${COLOR_PRINCIPAL};">${tit || "Título del correo"}</h1>
          </td>
        </tr>
        ${renderBloquesHTML(sufijo)}
        ${conPie ? piePagina : ""}
      </table>`;
  }
  // Funcion para generar el HTML completo
  function generarHTML() {
    const hojaEs = generarHoja(titulo, imagenCabecera, "", !hojaVaActiva);
    const hojaVa = hojaVaActiva
      ? generarHoja(tituloVa, imagenCabeceraVa, "Va", true)
      : "";

    return `<html>
    <head></head>
    <body>
      <table width="100%" cellspacing="0" cellpadding="0" border="0" bgcolor="#F2F4F7" style="margin:0;padding:0;">
        <tr>
        <td align="center" style="padding:20px 0;">${hojaEs}</td>
        </tr>
        ${hojaVaActiva ? `
          <tr>
          <td align="center" style="padding:20px 0;">${hojaVa}</td>
          </tr>` : ""}
      </table>
    </body>
    </html>`;
  }

  function generarBodyHTML() {
    const hojaEs = generarHoja(titulo, imagenCabecera, "", !hojaVaActiva);
    const hojaVa = hojaVaActiva
      ? generarHoja(tituloVa, imagenCabeceraVa, "Va", true)
      : "";

    return `<table width="100%" cellspacing="0" cellpadding="0" border="0" bgcolor="#F2F4F7" style="margin:0;padding:0;">
        <tr><td align="center" style="padding:20px 0;">${hojaEs}</td></tr>
        ${hojaVaActiva ? `<tr><td align="center" style="padding:20px 0;">${hojaVa}</td></tr>` : ""}
      </table>`;
  }

  function renderPanelBloques(esVa) {
    const sf = esVa ? "Va" : "";
    const sfCol2 = esVa ? "contenidoCol2Va" : "contenidoCol2";

    return bloques.map((b) => (
      <div key={b.id} style={{ border: "1px solid #ddd", borderRadius: 6, padding: 12, marginBottom: 12, background: "#fafafa" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong style={{ color: COLOR_PRINCIPAL }}>
            {b.tipo === "texto" && "Texto"}
            {b.tipo === "imagen" && "Imagen"}
            {b.tipo === "doscolumnas" && "Dos columnas"}
            {b.tipo === "caja" && "Texto en caja"}
            {b.tipo === "boton" && "Botón"}
          </strong>
          <button onClick={() => eliminarBloque(b.id)} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 16 }}>✕</button>
        </div>

        {b.tipo === "texto" && quillCargado && (
          <EditorQuill
            placeholder={esVa ? "Escriu el text ací..." : "Escribe el texto aquí..."}
            initialContent={b["contenido" + sf]}
            onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
          />
        )}

        {b.tipo === "imagen" && (
          <div>
            <input type="file" accept="image/*"
              onChange={e => imagenBloqueABase64(b.id, e.target.files[0], "imagen" + sf)}
              style={{ marginBottom: 8 }}
            />
            {b["imagen" + sf] && (
              <img src={b["imagen" + sf]} alt="preview" style={{ maxWidth: "100%", maxHeight: 100, display: "block", borderRadius: 4 }} />
            )}
          </div>
        )}

        {b.tipo === "doscolumnas" && quillCargado && (
          <div style={{ display: "flex", gap: 8 }}>
            <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
              <label style={{ fontSize: 12, fontWeight: "bold", display: "block", marginBottom: 4 }}>Columna 1</label>
              <EditorQuill
                placeholder={esVa ? "Text de la primera columna..." : "Texto de la primera columna..."}
                initialContent={b["contenido" + sf]}
                onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
              />
            </div>
            <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
              <label style={{ fontSize: 12, fontWeight: "bold", display: "block", marginBottom: 4 }}>Columna 2</label>
              <EditorQuill
                placeholder={esVa ? "Text de la segona columna..." : "Texto de la segunda columna..."}
                initialContent={b[sfCol2]}
                onReady={quill => guardarEditor(b.id, sfCol2, quill)}
              />
            </div>
          </div>
        )}

        {b.tipo === "caja" && quillCargado && (
          <EditorQuill
            placeholder={esVa ? "Text destacat a la caixa..." : "Texto destacado en la caja..."}
            initialContent={b["contenido" + sf]}
            onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
          />
        )}

        {b.tipo === "boton" && (
          <div style={{ display: "flex", gap: 8 }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>Texto del botón</label>
              <input type="text" value={b["textoBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "textoBoton" + sf, e.target.value)}
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
              />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>URL del enlace</label>
              <input type="text" value={b["urlBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "urlBoton" + sf, e.target.value)}
                placeholder="https://..."
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
              />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>Color</label>
              <select value={b["colorBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "colorBoton" + sf, e.target.value)}
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box", backgroundColor: "white" }}>
                <option value="#53565A">Gris</option>
                <option value={COLOR_PRINCIPAL}>Azul</option>
              </select>
            </div>
          </div>
        )}

        {["texto", "doscolumnas", "caja"].includes(b.tipo) && !quillCargado && (
          <p style={{ color: "#999", fontSize: 13 }}>Cargando editor...</p>
        )}
      </div>
    ));
  }

  // Aqui empieza el renderizado del componente principal
  return (
    <div style={{ display: "flex", height: "100%", width: "100%", overflow: "auto", fontFamily: "Arial, sans-serif" }}>

      {/* PANEL IZQUIERDO */}
      <div style={{ width: "33.33%", height: "100%", display: "flex", flexDirection: "column", borderRight: "2px solid #ddd", boxSizing: "border-box" }}>

        {/* Barra superior siempre visible */}
        <div style={{ padding: "12px 16px", borderBottom: "1px solid #ddd", display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0, background: "#fff" }}>
          <h2 style={{ color: COLOR_PRINCIPAL, margin: 0, fontSize: 18 }}>
            {mostrarListaCorreos
              ? "Correos guardados"
              : correoEditandoId ? `Editando: ${titulo || "Sin título"}` : "Nuevo correo"}
          </h2>
          <div style={{ display: "flex", gap: 6 }}>
            {!mostrarListaCorreos && (
              <button onClick={nuevoCorreo} title="Nuevo correo" style={estiloBotonIcono("#6b7280")}>
                <i className="bi bi-file-earmark-plus" />
              </button>
            )}
            <button
              onClick={() => setMostrarListaCorreos(v => !v)}
              title={mostrarListaCorreos ? "Volver al editor" : "Ver correos guardados"}
              style={estiloBotonIcono(mostrarListaCorreos ? COLOR_PRINCIPAL : "#6b7280")}
            >
              <i className={mostrarListaCorreos ? "bi bi-pencil-square" : "bi bi-folder2-open"} />
              {!mostrarListaCorreos && correosGuardados.length > 0 && (
                <span style={{
                  position: "absolute", top: -6, right: -6,
                  background: "#ef4444", color: "#fff",
                  borderRadius: "50%", width: 16, height: 16,
                  fontSize: 10, display: "flex", alignItems: "center", justifyContent: "center"
                }}>
                  {correosGuardados.length}
                </span>
              )}
            </button>
          </div>
        </div>

        {/* VISTA: Lista de correos guardados */}
        {mostrarListaCorreos ? (
          <div style={{ flex: 1, overflowY: "auto", padding: 16 }}>
            {correosGuardados.length === 0 ? (
              <div style={{ textAlign: "center", marginTop: 60, color: "#9ca3af" }}>
                <i className="bi bi-inbox" style={{ fontSize: 48, display: "block", marginBottom: 12 }} />
                <p style={{ fontSize: 14 }}>No hay correos guardados aún.</p>
                <button onClick={() => setMostrarListaCorreos(false)} style={{ marginTop: 8, padding: "8px 16px", background: COLOR_PRINCIPAL, color: "#fff", border: "none", borderRadius: 4, cursor: "pointer", fontSize: 13 }}>
                  Crear nuevo correo
                </button>
              </div>
            ) : (
              correosGuardados.map(correo => (
                <div key={correo.id}
                  onMouseEnter={() => setHoveredCorreoId(correo.id)}
                  onMouseLeave={() => setHoveredCorreoId(null)}
                  style={{
                    padding: "12px 14px", marginBottom: 10,
                    border: `1px solid ${correoEditandoId === correo.id ? COLOR_PRINCIPAL : "#e5e7eb"}`,
                    borderRadius: 6,
                    background: correoEditandoId === correo.id
                      ? "#EEF5FD"
                      : hoveredCorreoId === correo.id
                        ? "#f1f5f9"
                        : "#fff",
                    display: "flex", alignItems: "center", justifyContent: "space-between",
                    transition: "background 0.15s, border-color 0.15s",
                  }}
                >
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: "bold", fontSize: 14, color: "#1e293b", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                      {correo.titulo || "Sin título"}
                      {correo.hojaVaActiva && (
                        <span style={{ marginLeft: 6, fontSize: 10, background: "#dbeafe", color: COLOR_PRINCIPAL, borderRadius: 3, padding: "1px 5px" }}>ES+VA</span>
                      )}
                      {correo.esBorrador && (
                        <span style={{ marginLeft: 6, fontSize: 10, background: "#fef9c3", color: "#854d0e", borderRadius: 3, padding: "1px 5px" }}>Borrador</span>
                      )}
                    </div>
                    <div style={{ fontSize: 11, color: "#6b7280", marginTop: 3 }}>
                      <i className="bi bi-clock" style={{ marginRight: 4 }} />
                      {formatearFecha(correo.fechaModificacion)}
                    </div>
                    <div style={{ fontSize: 11, color: "#9ca3af", marginTop: 2 }}>
                      {correo.bloques.length} bloque{correo.bloques.length !== 1 ? "s" : ""}
                    </div>
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 6, marginLeft: 10, flexShrink: 0 }}>
                    <button
                      onClick={() => cargarCorreo(correo)}
                      title="Editar"
                      style={estiloBotonIconoPequeño(COLOR_PRINCIPAL)}
                    >
                      <i className="bi bi-pencil" />
                    </button>
                    <button
                      onClick={() => eliminarCorreoGuardado(correo.id)}
                      title="Eliminar"
                      style={estiloBotonIconoPequeño("#ef4444")}
                    >
                      <i className="bi bi-trash" />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>

        ) : (

          /* VISTA: Editor normal */
          <div style={{ flex: 1, overflowY: "auto", padding: 20, boxSizing: "border-box" }}>

            <div style={{ marginBottom: 15 }}>
              <button
                onClick={() => {
                  const nueva = !hojaVaActiva;
                  setHojaVaActiva(nueva);
                  setPestanaActiva(nueva ? "va" : "es");
                }}
                style={{
                  width: "160px",
                  padding: "9px 16px",
                  border: `2px solid ${hojaVaActiva ? COLOR_PRINCIPAL : "#ccc"}`,
                  borderRadius: 6,
                  cursor: "pointer",
                  fontWeight: "bold",
                  fontSize: 14,
                  background: hojaVaActiva ? "#EEF5FD" : "#f9f9f9",
                  color: hojaVaActiva ? COLOR_PRINCIPAL : "#888",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  gap: 10,
                  transition: "all 0.15s",
                }}>
                <span style={{
                  width: 20, height: 20, borderRadius: "50%",
                  border: `2px solid ${hojaVaActiva ? COLOR_PRINCIPAL : "#bbb"}`,
                  background: hojaVaActiva ? COLOR_PRINCIPAL : "transparent",
                  display: "inline-flex", alignItems: "center", justifyContent: "center",
                  color: "#fff", fontSize: 14, flexShrink: 0,
                }}>
                  {hojaVaActiva ? "✓" : ""}
                </span>
                Añadir copia
              </button>
            </div>

            {hojaVaActiva && (
              <div style={{ display: "flex", marginBottom: 20, borderBottom: `2px solid ${COLOR_PRINCIPAL}` }}>
                {["es", "va"].map(lang => (
                  <button key={lang} onClick={() => setPestanaActiva(lang)}
                    style={{
                      flex: 1, padding: "8px 0", border: "none", cursor: "pointer",
                      fontWeight: "bold", fontSize: 14,
                      background: pestanaActiva === lang ? COLOR_PRINCIPAL : "#e8f0fb",
                      color: pestanaActiva === lang ? "#fff" : COLOR_PRINCIPAL,
                      borderRadius: "4px 4px 0 0",
                      transition: "background 0.15s",
                    }}
                  >
                    {lang === "es" ? "Idioma 1" : "Idioma 2"}
                  </button>
                ))}
              </div>
            )}

            {/* Pestaña Español */}
            <div style={{ display: (!hojaVaActiva || pestanaActiva === "es") ? "block" : "none" }}>
              <div style={{ marginBottom: 25 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>
                  Imagen de cabecera <span style={{ fontWeight: "normal", color: "#999", fontSize: 12 }}>(opcional)</span>
                </label>
                <input type="file" accept="image/*" onChange={e => imagenCabeceraABase64(e.target.files[0], false)} />
                {imagenCabecera && (
                  <div>
                    <img src={imagenCabecera} alt="cabecera" style={{ maxWidth: "100%", maxHeight: 80, borderRadius: 4, display: "block", marginBottom: 4 }} />
                    <button onClick={() => setImagenCabecera("")} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 12, padding: 0 }}>
                      ✕ Quitar imagen
                    </button>
                  </div>
                )}
              </div>

              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>Título del correo</label>
                <input type="text" value={titulo} onChange={e => setTitulo(e.target.value)}
                  placeholder="Escribe el título aquí..."
                  style={{ width: "100%", padding: 8, fontSize: 14, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
                />
              </div>

              {bloques.length === 0 && (
                <p style={{ color: "#999", textAlign: "center", marginTop: 40 }}></p>
              )}

              <div key={"es-" + (correoEditandoId ?? "nuevo")}>
                {renderPanelBloques(false)}
              </div>

              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 8 }}>Añadir contenido:</label>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {["texto", "imagen", "doscolumnas", "caja", "boton"].map(tipo => (
                    <button key={tipo} onClick={() => agregarBloque(tipo)} style={estiloBotonAnadir} title={
                      tipo === "texto" ? "Texto" :
                        tipo === "imagen" ? "Imagen" :
                          tipo === "doscolumnas" ? "Dos columnas" :
                            tipo === "caja" ? "Texto en caja" : "Botón"
                    }>
                      <i className={
                        tipo === "texto" ? "bi bi-text-left" :
                          tipo === "imagen" ? "bi bi-image" :
                            tipo === "doscolumnas" ? "bi bi-layout-split" :
                              tipo === "caja" ? "bi bi-card-text" :
                                "bi bi-cursor"
                      } style={{ fontSize: 16 }} />
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Pestaña Valencià */}
            <div style={{ display: (hojaVaActiva && pestanaActiva === "va") ? "block" : "none" }}>
              <div style={{ marginBottom: 25 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>
                  Imatge de capçalera <span style={{ fontWeight: "normal", color: "#999", fontSize: 12 }}>(opcional)</span>
                </label>
                <input type="file" accept="image/*" onChange={e => imagenCabeceraABase64(e.target.files[0], true)} />
                {imagenCabeceraVa && (
                  <div>
                    <img src={imagenCabeceraVa} alt="cabecera" style={{ maxWidth: "100%", maxHeight: 80, borderRadius: 4, display: "block", marginBottom: 4 }} />
                    <button onClick={() => setImagenCabeceraVa("")} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 12, padding: 0 }}>
                      ✕ Llevar imatge
                    </button>
                  </div>
                )}
              </div>

              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>Títol del correu</label>
                <input type="text" value={tituloVa} onChange={e => setTituloVa(e.target.value)}
                  placeholder="Escriu el títol ací..."
                  style={{ width: "100%", padding: 8, fontSize: 14, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
                />
              </div>

              {bloques.length === 0 && (
                <p style={{ color: "#999", textAlign: "center", marginTop: 40 }}></p>
              )}

              <div key={"va-" + (correoEditandoId ?? "nuevo")}>
                {renderPanelBloques(true)}
              </div>

              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontWeight: "bold", marginBottom: 8 }}>Afegir contingut:</label>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {["texto", "imagen", "doscolumnas", "caja", "boton"].map(tipo => (
                    <button key={tipo} onClick={() => agregarBloque(tipo)} style={estiloBotonAnadir} title={
                      tipo === "texto" ? "Texto" :
                        tipo === "imagen" ? "Imagen" :
                          tipo === "doscolumnas" ? "Dos columnas" :
                            tipo === "caja" ? "Texto en caja" : "Botón"
                    }>
                      <i className={
                        tipo === "texto" ? "bi bi-text-left" :
                          tipo === "imagen" ? "bi bi-image" :
                            tipo === "doscolumnas" ? "bi bi-layout-split" :
                              tipo === "caja" ? "bi bi-card-text" :
                                "bi bi-link-45deg"
                      } style={{ fontSize: 16 }} />
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Botones inferiores */}
            <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
              <button onClick={guardarCorreo}
                style={{
                  flex: 1, padding: 10,
                  background: COLOR_PRINCIPAL, color: "#fff",
                  border: "none", borderRadius: 4, cursor: "pointer",
                  fontSize: 14, fontWeight: "bold"
                }}>
                <i className="bi bi-floppy" style={{ marginRight: 6 }} />
                {correoEditandoId ? "Actualizar correo" : "Guardar correo"}
              </button>
              <button onClick={copiarHTML}
                style={{
                  flex: 1, padding: 10,
                  background: copiado ? "#16a34a" : "#1e293b",
                  color: "#fff", border: "none", borderRadius: 4,
                  cursor: "pointer", fontSize: 14, fontWeight: "bold"
                }}>
                {copiado ? "Copiado ✅" : "Copiar HTML 📋"}
              </button>
            </div>

          </div>
        )}
      </div>

      {/* PANEL DERECHO - Preview */}
      <div style={{ width: "66.66%", height: "100%", display: "flex", flexDirection: "column" }}>
        <div style={{ background: "#333", color: "#ccc", padding: "8px 16px", fontSize: 12, flexShrink: 0 }}>
          Vista previa del correo{hojaVaActiva ? " (Español + Valencià)" : " (Español)"}
        </div>
        <iframe ref={iframeRef} style={{ flex: 1, width: "100%", border: "none" }} title="preview" />
      </div>

    </div>
  );
}

const estiloBotonAnadir = {
  padding: "7px 14px",
  background: COLOR_PRINCIPAL,
  color: "#fff",
  border: "none",
  borderRadius: 4,
  cursor: "pointer",
  fontSize: 13,
};

const estiloBotonIcono = (color) => ({
  position: "relative", padding: "6px 10px",
  background: "none", border: `1px solid ${color}`,
  borderRadius: 4, cursor: "pointer", color, fontSize: 16,
  display: "flex", alignItems: "center",
});

const estiloBotonIconoPequeño = (color) => ({
  padding: "4px 7px", background: "none",
  border: `1px solid ${color}`, borderRadius: 4,
  cursor: "pointer", color, fontSize: 13,
  display: "flex", alignItems: "center",
});

